43	func (s *Server) handleCreateHost(w http.ResponseWriter, r *http.Request) {
44		var req createHostRequest
45		if err := decodeJSONStrict(r, &req); err != nil {
46			writeError(w, http.StatusBadRequest, err.Error())
47			return
48		}
49	
50		if req.Name == "" || len(req.NebulaIPs) == 0 || req.NetworkID == "" {
51			writeError(w, http.StatusBadRequest, "name, nebula_ips, and network_id are required")
52			return
53		}
54		if err := validateHostIPs(r.Context(), s.store, req.NetworkID, req.NebulaIPs, ""); err != nil {
55			if IsHostIPValidationError(err) {
56				writeError(w, http.StatusBadRequest, err.Error())
57				return
58			}
59			s.logger.Error("validate host ips", "error", err)
60			writeError(w, http.StatusInternalServerError, "failed to validate nebula_ips")
61			return
62		}
63		if req.ListenPort < 0 || req.ListenPort > 65535 {
64			writeError(w, http.StatusBadRequest, "listen_port must be between 0 and 65535")
65			return
66		}
67	
68		if strings.TrimSpace(req.PublicIP) != "" {
69			if _, err := models.ValidateIPAddr("public_ip", req.PublicIP); err != nil {
70				writeError(w, http.StatusBadRequest, err.Error())
71				return
72			}
73		}
74	
75		role := models.HostRole(req.Role)
76		if !models.ValidRole(role) {
77			writeError(w, http.StatusBadRequest, fmt.Sprintf("invalid role: %q", req.Role))
78			return
79		}
80		if role == "" {
81			role = models.HostRoleHost
82		}
83		if err := models.ValidateRoleReachability(role, req.PublicIP, req.ListenPort); err != nil {
84			writeError(w, http.StatusBadRequest, err.Error())
85			return
86		}
87	
88		if err := validateHostAdvanced(req.Advanced); err != nil {
89			writeError(w, http.StatusBadRequest, err.Error())
90			return
91		}
92	
93		now := time.Now()
94		host := &models.Host{
95			ID:           uuid.New().String(),
96			NetworkID:    req.NetworkID,
97			Name:         req.Name,
98			NebulaIPs:    req.NebulaIPs,
99			Groups:       req.Groups,
100			Role:         role,
101			IsLighthouse: role == models.HostRoleLighthouse,
102			IsRelay:      role == models.HostRoleRelay,
103			PublicIP:     req.PublicIP,
104			ListenPort:   req.ListenPort,
105			Status:       models.HostStatusPending,
106			Advanced:     req.Advanced,
107			CAID:         s.defaultCAID,
108			CreatedAt:    now,
109			UpdatedAt:    now,
110		}
111		if host.Groups == nil {
112			host.Groups = []string{}
113		}
114		for _, g := range host.Groups {
115			if strings.TrimSpace(g) == "" {
116				writeError(w, http.StatusBadRequest, "group names must not be empty")
117				return
118			}
119		}
120	
121		token := &models.EnrollmentToken{
122			ID:        uuid.New().String(),
123			HostID:    host.ID,
124			Token:     uuid.New().String(),
125			ExpiresAt: now.Add(s.tokenTTLFor(r.Context(), host.NetworkID)),
126			CreatedAt: now,
127		}
128		if err := s.store.CreateHostAndToken(r.Context(), host, token); err != nil {
129			s.logger.Error("create host and token", "error", err)
130			writeError(w, http.StatusInternalServerError, "failed to create host")
131			return
132		}
133		s.recordAuditAction(r.Context(), auditHostCreate, host.ID, host.Name)
134	
135		writeJSON(w, http.StatusCreated, createHostResponse{
136			Host:            host,
137			EnrollmentToken: token.Token,
138		})
139	}
