226		if err != nil {
227			s.logger.Error("get blocklist", "error", err)
228			writeError(w, http.StatusInternalServerError, "failed to get blocklist")
229			return
230		}
231		if list == nil {
232			list = []string{}
233		}
234	
235		writeJSON(w, http.StatusOK, list)
236	}
237	
238	type regenerateEnrollmentTokenResponse struct {
239		Token     string    `json:"token"`
240		ExpiresAt time.Time `json:"expires_at"`
241	}
242	
243	type rotateCertResponse struct {
244		NewKey         bool   `json:"new_key"`
245		CertificatePEM string `json:"certificate_pem,omitempty"`
246		CACertPEM      string `json:"ca_certificate_pem,omitempty"`
247	}
248	
249	// handleRotateCert implements POST /api/v1/hosts/{id}/rotate-cert?new_key=...
250	// (ADR 0004 §7.1 force-rotate).
251	//
252	//   - new_key=false (default): the server re-signs the existing public key
253	//     immediately and returns the new cert. The agent picks it up on the
254	//     next poll via SaveCertificateAndUpdateHostCert's overlap window.
255	//   - new_key=true: a pending_rekey flag is set on the host row. The next
256	//     poll response carries rekey_required + a single-use enrollment token
257	//     the agent uses to re-enroll its freshly generated keypair.
258	func (s *Server) handleRotateCert(w http.ResponseWriter, r *http.Request) {
259		id := chi.URLParam(r, "id")
260		newKey := strings.EqualFold(r.URL.Query().Get("new_key"), "true")
261	
262		host, err := s.store.GetHost(r.Context(), id)
263		if errors.Is(err, store.ErrNotFound) {
264			writeError(w, http.StatusNotFound, "host not found")
265			return
266		}
267		if err != nil {
268			s.logger.Error("get host for rotate-cert", "error", err)
269			writeError(w, http.StatusInternalServerError, "failed to get host")
270			return
271		}
272	
273		if newKey {
274			if err := s.store.SetPendingRekey(r.Context(), host.ID); err != nil {
275				if errors.Is(err, store.ErrRekeyAlreadyPending) {
276					writeError(w, http.StatusConflict, "rekey already pending")
277					return
278				}
279				s.logger.Error("set pending rekey", "error", err)
280				writeError(w, http.StatusInternalServerError, "failed to schedule rekey")
281				return
282			}
283			s.recordAuditAction(r.Context(), auditHostRotateCertRequested, host.ID, "new_key=true")
284			writeJSON(w, http.StatusAccepted, rotateCertResponse{NewKey: true})
285			return
286		}
287	
288		certInfo, err := s.store.GetCertificateInfo(r.Context(), host.ID)
289		if err != nil {
290			s.logger.Error("get cert info for rotate-cert", "error", err)
291			writeError(w, http.StatusInternalServerError, "no current cert to re-sign")
292			return
293		}
294		signed, err := s.signHostCert(r.Context(), host, certInfo)
295		if err != nil {
296			s.logger.Error("sign cert for rotate-cert", "error", err)
297			writeError(w, http.StatusInternalServerError, "failed to sign new cert")
298			return
299		}
300		if err := s.store.SaveCertificateAndUpdateHostCert(r.Context(), host.ID, signed.certPEM, signed.fp, signed.notBefore, signed.notAfter); err != nil {
301			s.logger.Error("save rotated cert", "error", err)
302			writeError(w, http.StatusInternalServerError, "failed to persist new cert")
303			return
304		}
305		s.metrics.recordSignature(host.CAID)
306		s.recordAuditAction(r.Context(), auditHostRotateCertRequested, host.ID, "new_key=false")
307	
308		writeJSON(w, http.StatusOK, rotateCertResponse{
309			NewKey:         false,
310			CertificatePEM: string(signed.certPEM),
311			CACertPEM:      string(signed.caCertPEM),
312		})
313	}
314	
315	// handleReenroll is the explicit re-enrollment endpoint (ADR 0004 §7.1).
316	// It delegates to mintEnrollmentTokenForHost — identical mechanics to
317	// handleRegenerateEnrollmentToken — but exists as a separate route so
318	// operator UIs can present "re-enroll" as a discrete action (e.g. when a
319	// host has lost its key material), distinct from the "regenerate token"
320	// fix-up that handleRegenerateEnrollmentToken serves.
321	func (s *Server) handleReenroll(w http.ResponseWriter, r *http.Request) {
322		s.mintEnrollmentTokenForHost(w, r, "reenroll")
323	}
324	
325	// handleRegenerateEnrollmentToken mints a fresh single-use enrollment token
326	// bound to an existing host row (ADR 0004 §7.1 — "regenerates the token
327	// without churning the row"). Previous active tokens for the same host are
328	// invalidated atomically. The host row, its IP allocation, group membership,
329	// and audit history are preserved.
330	func (s *Server) handleRegenerateEnrollmentToken(w http.ResponseWriter, r *http.Request) {
331		s.mintEnrollmentTokenForHost(w, r, "regenerate-token")
332	}
333	
334	// mintEnrollmentTokenForHost is the shared implementation of the
335	// regenerate-token and reenroll endpoints. The reason argument flows into
336	// the audit details column so the timeline distinguishes the two.
337	func (s *Server) mintEnrollmentTokenForHost(w http.ResponseWriter, r *http.Request, reason string) {
338		id := chi.URLParam(r, "id")
339		host, err := s.store.GetHost(r.Context(), id)
340		if errors.Is(err, store.ErrNotFound) {
341			writeError(w, http.StatusNotFound, "host not found")
342			return
343		}
344		if err != nil {
345			s.logger.Error("get host", "error", err)
346			writeError(w, http.StatusInternalServerError, "failed to get host")
347			return
348		}
349	
350		tokenStr := uuid.New().String()
351		expiresAt := time.Now().Add(s.tokenTTLFor(r.Context(), host.NetworkID))
352		if err := s.store.CreateTokenForHost(r.Context(), host.ID, tokenStr, expiresAt); err != nil {
353			s.logger.Error("create enrollment token", "error", err)
354			writeError(w, http.StatusInternalServerError, "failed to mint token")
355			return
356		}
357		details := host.Name
358		if reason != "" {
359			details = reason + ": " + host.Name
360		}
361		s.recordAuditAction(r.Context(), auditHostReenrollRequested, host.ID, details)
362	
363		writeJSON(w, http.StatusCreated, regenerateEnrollmentTokenResponse{
364			Token:     tokenStr,
365			ExpiresAt: expiresAt,
366		})
367	}
368	
369	func (s *Server) handleUpdateHost(w http.ResponseWriter, r *http.Request) {
370		id := chi.URLParam(r, "id")
371	
372		// Load host by ID
373		host, err := s.store.GetHost(r.Context(), id)
374		if errors.Is(err, store.ErrNotFound) {
375			writeError(w, http.StatusNotFound, "host not found")
376			return
377		}
378		if err != nil {
379			s.logger.Error("get host", "error", err)
380			writeError(w, http.StatusInternalServerError, "failed to get host")
381			return
382		}
383	
384		// API trusts the bearer token for authorisation; per-CA ownership is enforced only in the Web layer (handleHostUpdate). Matches handleCreateHost/handleDeleteHost behaviour.
385	
386		// Decode request body (lenient for PATCH, forward-compatible)
387		var req updateHostRequest
388		if err := json.NewDecoder(r.Body).Decode(&req); err != nil {
389			writeError(w, http.StatusBadRequest, "invalid request body")
390			return
391		}
392	
393		// Snapshot before state for diff and triggers
394		before := *host
395		if before.Advanced != nil {
396			beforeAdv := *before.Advanced
397			before.Advanced = &beforeAdv
398		}
399	
400		// Validate and merge fields
401		if req.Name != nil {
402			name := strings.TrimSpace(*req.Name)
403			if name == "" {
404				writeError(w, http.StatusBadRequest, "name must not be empty")
405				return
406			}
407			host.Name = name
408		}
409	
410		if req.NebulaIPs != nil {
411			if err := validateHostIPs(r.Context(), s.store, host.NetworkID, *req.NebulaIPs, host.ID); err != nil {
412				if IsHostIPValidationError(err) {
413					writeError(w, http.StatusBadRequest, err.Error())
414					return
415				}
416				s.logger.Error("validate host ips", "error", err)
417				writeError(w, http.StatusInternalServerError, "failed to validate nebula_ips")
418				return
419			}
420			host.NebulaIPs = *req.NebulaIPs
421		}
422	
423		if req.Groups != nil {
424			for _, g := range *req.Groups {
425				if strings.TrimSpace(g) == "" {
426					writeError(w, http.StatusBadRequest, "group names must not be empty")
427					return
428				}
429			}
430			host.Groups = *req.Groups
431		}
432	
433		if req.Role != nil {
434			role := models.HostRole(*req.Role)
435			if !models.ValidRole(role) {
436				writeError(w, http.StatusBadRequest, fmt.Sprintf("invalid role: %q", *req.Role))
437				return
438			}
439			host.Role = role
440			host.IsLighthouse = role == models.HostRoleLighthouse
441			host.IsRelay = role == models.HostRoleRelay
442		}
443	
444		if req.PublicIP != nil {
445			publicIP := strings.TrimSpace(*req.PublicIP)
446			if publicIP != "" {
447				if _, err := models.ValidateIPAddr("public_ip", publicIP); err != nil {
448					writeError(w, http.StatusBadRequest, err.Error())
449					return
450				}
451			}
452			host.PublicIP = publicIP
453		}
454	
455		if req.ListenPort != nil {
456			if *req.ListenPort < 0 || *req.ListenPort > 65535 {
457				writeError(w, http.StatusBadRequest, "listen_port must be between 0 and 65535")
458				return
459			}
460			host.ListenPort = *req.ListenPort
461		}
462	
463		if req.Advanced != nil {
464			if err := validateHostAdvanced(req.Advanced); err != nil {
465				writeError(w, http.StatusBadRequest, err.Error())
466				return
467			}
468			host.Advanced = req.Advanced
469		}
470	
471		// Validate role reachability
472		if err := models.ValidateRoleReachability(host.Role, host.PublicIP, host.ListenPort); err != nil {
473			writeError(w, http.StatusBadRequest, err.Error())
474			return
475		}
476	
477		// Compute diff
478		diffJSON, hasChanges, err := models.HostDiff(&before, host)
479		if err != nil {
480			s.logger.Error("compute diff", "error", err)
481			writeError(w, http.StatusInternalServerError, "failed to compute diff")
482			return
483		}
484	
485		// If no changes, return 200 without updating
486		if !hasChanges {
487			writeJSON(w, http.StatusOK, host)
488			return
489		}
490	
491		// Update timestamp and persist
492		host.UpdatedAt = time.Now()
493		if err := s.store.UpdateHost(r.Context(), host); err != nil {
494			s.logger.Error("update host", "error", err)
495			writeError(w, http.StatusInternalServerError, "failed to update host")
496			return
497		}
498	
499		// Task 1.4: Re-publish triggers
500		// Force re-publish config for this host
501		if err := s.store.UpdateHostConfigVersion(r.Context(), host.ID, 0); err != nil {
502			s.logger.Error("reset host config version", "host", host.ID, "error", err)
503		}
504	
505		// If role changed, bump network config version for peer updates
506		if before.Role != host.Role {
507			if err := s.store.BumpNetworkConfigVersion(r.Context(), host.NetworkID); err != nil {
508				s.logger.Error("bump network config version", "network", host.NetworkID, "error", err)
509			}
510		}
511	
512		// If name or any IP changed, set pending rekey for cert re-enrollment
513		ipsEqual := len(before.NebulaIPs) == len(host.NebulaIPs)
514		if ipsEqual {
515			for i := range before.NebulaIPs {
516				if before.NebulaIPs[i] != host.NebulaIPs[i] {
517					ipsEqual = false
518					break
519				}
520			}
521		}
522		if before.Name != host.Name || !ipsEqual {
523			if err := s.store.SetPendingRekey(r.Context(), host.ID); err != nil {
524				if !errors.Is(err, store.ErrRekeyAlreadyPending) {
525					s.logger.Error("set pending rekey", "host", host.ID, "error", err)
526				}
527				// Idempotent: ErrRekeyAlreadyPending is success (rekey already scheduled)
528			}
529			// Reload host to get PendingRekey flag in response
530			freshHost, err := s.store.GetHost(r.Context(), host.ID)
531			if err == nil {
532				host = freshHost
533			}
534		}
535	
536		// Record audit entry with diff
537		s.recordAuditAction(r.Context(), auditHostUpdate, host.ID, string(diffJSON))
538	
539		writeJSON(w, http.StatusOK, host)
540	}
