1	package api
2	
3	import (
4		"net/http"
5		"strconv"
6	
7		"github.com/juev/nebula-mesh/internal/store"
8	)
9	
10	const defaultAuditLimit = 100
11	
12	func (s *Server) handleGetAuditLog(w http.ResponseWriter, r *http.Request) {
13		filter := store.AuditFilter{
14			Action: r.URL.Query().Get("action"),
15			Limit:  defaultAuditLimit,
16		}
17		if l := r.URL.Query().Get("limit"); l != "" {
18			n, err := strconv.Atoi(l)
19			if err != nil {
20				writeError(w, http.StatusBadRequest, "invalid limit: must be a number")
21				return
22			}
23			if n < 1 {
24				writeError(w, http.StatusBadRequest, "invalid limit: must be positive")
25				return
26			}
27			if n > 1000 {
28				n = 1000
29			}
30			filter.Limit = n
31		}
32	
33		entries, err := s.store.ListAuditEntries(r.Context(), filter)
34		if err != nil {
35			s.logger.Error("list audit entries", "error", err)
36			writeError(w, http.StatusInternalServerError, "failed to get audit log")
37			return
